/*
Form Script Name: UpdateDocumentPath
Customer:         WADNR
Purpose:          Resolve the upload folder path for the Notice to Comply form based on the presence of the NTC Number.

Parameters:

Revision(s):
            09/24/2025 - Matías Andrade: Initial setup.
*/

// Read fields
const ntcNumber = VV.Form.GetFieldValue("NTC Number");
const formID = VV.Form.GetFieldValue("Form ID");

// Default to TEMP: /ENFORCEMENT/TEMP/[FORM ID]
let documentUploadPath = `/ENFORCEMENT/TEMP/${formID}`;

// Regex to verify if NTC Number follows pattern __-__-YY-NNNNN
const regex = /^[^-]+-[^-]+-\d{2}-\d+$/;

// If NTC Number is valid, switch to FINAL: /ENFORCEMENT/[YYYY]/[Range]/[NTC NUMBER]
if (ntcNumber != "" && regex.test(ntcNumber)) {
  // Reuse helper to derive "YYYY/Range/NTC_NUMBER"
  let ntcNumberParamsPath = VV.Form.Global.GetFolderPathFromFPANumber(ntcNumber);
  if (ntcNumberParamsPath != "") {
    documentUploadPath = `/ENFORCEMENT/${ntcNumberParamsPath}`;
  }
}

// Persist the resolved path into the hidden field
return VV.Form.SetFieldValue("Document Upload Path", documentUploadPath);

//Submit for Notice to Comply
/*
Form Script Name: Submit
Customer:         WADNR
Purpose:          Submit script for Notice to Comply form.

Parameters:

Revision(s):
            --/--/---- - previous developer: previous changes.
            01/30/2026 - Matías Andrade: Set Manage Status field to Submitted.
            02/13/2025 - Zharich Barona: Added logic to relate enforcement records after submission only if not in offline mode.
*/
const isFPANumberSet =
  VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('FPAN Number'), 'Blank') == true;
const isOfflineMode = VV.Form.IsOfflineMode === true;

const promiseForSubmission = [
  VV.Form.Template.CallLibFPETSNumberGenerate()
];

const promiseForRelateToARP = isFPANumberSet ? VV.Form.Template.CallNTCRelateToARP() : Promise.resolve();

Promise.all(promiseForSubmission)
  .then(([{ numberIdentifier }]) => {
    return Promise.all([
      VV.Form.SetFieldValue('Submitted Date', new Date()),
      VV.Form.SetFieldValue('NTC Number', numberIdentifier),
      VV.Form.SetFieldValue('Status', 'Submitted'),
      VV.Form.SetFieldValue('Manage Status', 'Submitted'),
      VV.Form.EvaluateGroupConditions()
    ]);
  })
  .then(() => VV.Form.DoAjaxFormSave())
  .then(() => {
    if (isOfflineMode) {
      return Promise.resolve();
    }
    return VV.Form.Template.RelateEnforcementRecords().catch((err) => {
      console.error('Error relating enforcement records:', err);
    });
  })
  .then(() => promiseForRelateToARP)
  .then(() => {
    VV.Form.Global.DisplayModal({
      Icon: 'success',
      Title: 'Form Submitted',
      HtmlContent: 'The Form has been submitted successfully.',
    });
  })
  .catch((err) => {
    console.log(err);
    VV.Form.Global.DisplayModal({
      Title: 'Error',
      Icon: 'error',
      HtmlContent:
        'An error occurred while attempting to submit the form. Please check your inputs and try again.',
    });
  });

if (data) {
  // Set Region from ARP
  if (data.region) {
    VV.Form.SetFieldValue("Region", data.region.trim());
  }

  // Set FPAN Number if not already set
  if (data.fpanNumber && !VV.Form.GetFieldValue("FPAN Number")) {
    VV.Form.SetFieldValue("FPAN Number", data.fpanNumber);
  }

  // Set Class of Forest Practice from ARP fpanClassification
  if (data.fpanClassification) {
    VV.Form.SetFieldValue("Class of Forest Practice", data.fpanClassification);
  }

  // Set Compliance Officer fields from Position Management data
  if (data.complianceOfficerName) {
    VV.Form.SetFieldValue("Name of DNR Compliance Officer", data.complianceOfficerName);
  }

  if (data.complianceOfficerTitle) {
    VV.Form.SetFieldValue("Title of Compliance Officer", data.complianceOfficerTitle);
  }

  if (data.complianceOfficerPositionNumber) {
    VV.Form.SetFieldValue("Position Number", data.complianceOfficerPositionNumber);
  }

  // Refresh data grids to show the newly created Contact Information Relation records
  VV.Form.RefreshDataGridControl("DG Landowner Businesses");
  VV.Form.RefreshDataGridControl("DG Landowners");
  VV.Form.RefreshDataGridControl("DG Timber Owner Businesses");
  VV.Form.RefreshDataGridControl("DG Timber Owner Individual");
  VV.Form.RefreshDataGridControl("DG Operator Businesses");
  VV.Form.RefreshDataGridControl("DG Operators");

  // Refresh RowRepeatControl for Legal Description (RRC Legal Description)
  // Note: RRC Legal Description is a RowRepeatControl, not a DataGrid
  // The Legal Description records are created by the web service and will appear
  // in the RowRepeatControl when it's refreshed
  try {
    // Try refreshing as RowRepeatControl first
    VV.Form.RefreshRowRepeatControl("RRC Legal Description");
  } catch (e) {
    // If that doesn't work, try as DataGrid (in case it's actually a DataGrid)
    try {
      VV.Form.RefreshDataGridControl("RRC Legal Description");
    } catch (e2) {
      // If neither works, try alternative names
      try {
        VV.Form.RefreshRowRepeatControl("DG Legal Description");
      } catch (e3) {
        try {
          VV.Form.RefreshDataGridControl("DG Legal Description");
        } catch (e4) {
          // If none exist, log but don't fail
          console.log("Could not refresh Legal Description control");
        }
      }
    }
  }

  // Refresh RowRepeatControl
  VV.Form.Global.RefreshFormElements();
}

/*
 * RemoveSelectedContactInformationRelation
 * This is the name of the web service that will be called from the server-side.
 * Make sure to replace "RemoveSelectedLandownersBusiness" with your actual web service name.
 *
 * Note: Make sure that your server-side script is configured to call the web service and handle the response.
 *
 * PARAMETERS:
 *              - SelectedItems: Array (Collection of Landowners GUIDs)
 *              - removedName: String 
 *              - type: String (Type of relation being removed)
 *              - isBusinessSigner: Boolean (Indicates if the relation is a business signer)
 */

const websvcName = "LibRemoveContactInformationRelation";

const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  const formData = [
    {
      name: "Form ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Selected Item IDs",
      value: SelectedItems,
    },
    {
      name: "Removed Name",
      value: removedName
    },
    {
      name: "Type",
      value: type
    }
  ];

  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();

  let messageData = "";

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] != "undefined") {
      if (resp.data[0] == "Success") {
        messageData = `${type} record(s) removed successfully`;

        VV.Form.Global.RefreshFormElements();

        VV.Form.Global.DisplayModal({
          Icon: "success",
          Title: "Success",
          HtmlContent: messageData,
        });
        return;
      } else if (resp.data[0] == "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: "Error",
    Icon: "error",
    HtmlContent: messageData,
  });
}

const websvcName = "LibRelateEnforcementRecords";

const deferred = $.Deferred();
const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Enforcement Form ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Enforcement Numbers",
      value: VV.Form.GetFieldValue("Related Enforcement Numbers"),
    },
  ];

  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = "";
  let resolvePromise = false;
  let callData = {};

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {
        resolvePromise = true;
        callData = resp.data[1];
      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve(callData);
  } else {
    deferred.reject(messageData);
  }
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: "Error",
    Icon: "error",
    HtmlContent: messageData,
  });
}

return deferred.promise();

