const webServiceName = "LoadDataFromTheARPForNTC";

// Make the execution to async
const deferred = $.Deferred();

let message; // the message is set below

// Check if we have data to load before proceeding
const fpanNumber = VV.Form.GetFieldValue("FPAN Number");
const relatedRecordID = VV.Form.GetFieldValue("Related Record ID");

// If no data is available, return early without showing loading panel
if ((!relatedRecordID || relatedRecordID === "") && (!fpanNumber || fpanNumber === "")) {
  return;
}

VV.Form.ShowLoadingPanel();

function CallServerSide() {
  let formData = [];

  // Always include Form ID (NTC Form ID) - required by web service
  formData.push({
    name: "Form ID",
    value: VV.Form.DhDocID,
  });

  // Use Related Record ID if available, otherwise use FPAN Number
  if (relatedRecordID && relatedRecordID !== "") {
    formData.push({
      name: "Related Record ID",
      value: relatedRecordID,
    });
  } else if (fpanNumber && fpanNumber !== "") {
    // Normalize the number (uppercase, trim)
    // Handle comma-separated list - use first number
    const normalizedNumber = fpanNumber
      .split(",")[0]
      .trim()
      .toUpperCase();

    formData.push({
      name: "FPAN Number",
      value: normalizedNumber,
    });
  }

  // Parse the data as a JSON string
  const data = JSON.stringify(formData);

  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
    contentType: "application/json; charset=utf-8",
    data: data,
    success: "",
    error: "",
  });

  return requestObject;
}

$.when(CallServerSide()).always(function (resp) {
  let messageData = "";
  let resolvePromise = false;
  let callData = {};

  VV.Form.HideLoadingPanel();

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;

    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;

    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {

        const data = resp.data[2]?.results;

        Promise.all([
            VV.Form.Template.PopulateARPData(data),
            VV.Form.SetFieldValue("Was AutoPopulated", "True")
        ])
            .then(() => resolvePromise = true);



      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[2] || ''}`; 
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
      }
    } else {
      messageData = "The status of the response returned as undefined.";
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
  }
  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve(callData);
  } else {
    deferred.reject({
        message: 'Error',
        messageDetail: messageData
    });
  }
});

return deferred.promise();

