/*
    Function Name: ManageStatus_onChange - Notice to Comply (NTC)
    Customer:      Washington DNR
    Purpose:       onChange handler for the "Manage Status" dropdown in the Manage tab.
                   Immediately prompts for confirmation and, on approval, updates the record Status,
                   saves the form, and triggers Associated Document Relation updates.

    Parameters:    event - New selected value for "Manage Status"

    Date of Dev:   02/09/2026
    Last Rev Date: 02/09/2026

    02/09/2026 - Matias Andrade: Moved status confirmation from Save to Manage Status onChange. Added non-dismissible modal and ensured Status/Manage Status remain in sync.
*/

const newManageStatus = event;
const recordStatus = VV.Form.GetFieldValue("Status");

const formID = VV.Form.DhDocID;
const formTemplateType = "Notice to Comply";
const sensitiveSite = false;

if (newManageStatus !== recordStatus) {
  VV.Form.Global.DisplayModal({
    Title: "Confirmation",
    Icon: "question",
    HtmlContent: "<p>Do you want to change the current NTC Status?</p>",
    showCancelButton: false,
    showDenyButton: true,
    ConfirmText: "Yes",
    SecondaryText: "No",
    allowOutsideClick: false,
    allowEscapeKey: false,

    okFunction: () => {
      return Promise.resolve()
        .then(() => VV.Form.SetFieldValue("Status", newManageStatus))
        .then(() => VV.Form.DoAjaxFormSave())
        .then(() =>
          VV.Form.Global.CallLibAssociatedDocumentRelationUpdate(
            formID,
            formTemplateType,
            sensitiveSite
          )
        )
        .then(() => {
          if (window.opener?.VV?.Form) {
            window.opener.VV.Form.RefreshDataGridControl("DG Associated Documents");
          }

          VV.Form.Global.DisplayModal({
            Icon: "success",
            Title: "Success",
            HtmlContent: "<i>NTC Status successfully updated.</i>",
            showCancelButton: false,
            allowOutsideClick: false,
            allowEscapeKey: false,
          });
        })
        .catch((error) => {
          console.log(error?.message || error);

          // Keep UI in sync with record status on error
          return VV.Form.SetFieldValue("Manage Status", recordStatus).then(() => {
            VV.Form.Global.DisplayModal({
              Title: "Error",
              Icon: "error",
              HtmlContent:
                "An error occurred while updating the status. Please try again or contact support if the issue persists.",
            });
          });
        });
    },

    secondFunction: () => {
      // User clicked "No" → revert Manage dropdown to current record status
      return VV.Form.SetFieldValue("Manage Status", recordStatus);
    },
  });
}

