                const currentFormId = VV.Form.GetFieldValue('Form ID');
                VV.Form.SetFieldValue('Offline Initial Form ID', String(currentFormId), true);
            }
        })
        .then(() => {
            // Now save AFTER fields have been updated
            return VV.Form.Template.SaveDraft();
        })
        .catch((err) => {
            console.error('Error during Save Draft offline chain:', err);
        });

} catch (err) {
    console.error('Outer error in Save Draft click handler:', err);
    VV.Form.Template.SaveDraft();
}

