/*
Form Script Name: Form_onLoad
Customer:         WADNR
Purpose:          Form onLoad script for Notice to Comply form.

Parameters:

Revision(s):
            09/23/2025 - Matías Andrade: Initial setup.
            09/25/2025 - Mauro Rapuano: Register all DGs.
            09/25/2025 - Lucas Herrera: load FPAN relations.
            10/20/2025 - Sebastian Rolando: Add logic for Offline Form.
            01/30/2026 - Matías Andrade: Fix mispellings error in setting field name and fix an error in LoadDataFromTheARP call.
            02/13/2026 - Federico Cuelho: Refactor to init save to prevent issues with loading data from ARP and added error handling to catch blocks.
*/

// Set the current status of the form
try {
  const formStatus = VV.Form.GetFieldValue('Status');

  if (VV.Form.Global.isNullEmptyUndefined(formStatus)) {
    Promise.all([
      VV.Form.SetFieldValue('Status', 'Draft'),
      VV.Form.SetFieldValue('Manage Status', 'Draft'),
    ]);
  }
} catch (error) {
  console.error('Error setting initial Status fields:', error);
}

try {
  // Get roles directly (synchronous)
  const roles = VV.Form.Global.GetCurrentRoles();

  Promise.resolve().then(() => {
    // Set User Roles field
    VV.Form.SetFieldValue('User Roles', roles);

    // Check role types in a single pass
    const isOfficeStaff =
      roles.includes('office staff') ||
      roles.includes('vaultaccess') ||
      roles.includes('management');

    const isProponent = roles.includes('proponent');

    const isFieldStaff = roles.includes('field staff');

    // Set values based on Office Staff role
    if (isOfficeStaff) {
      VV.Form.SetFieldValue('IsOfficeStaff', 'True', true);
    } else {
      VV.Form.SetFieldValue('IsOfficeStaff', 'False');
    }

    // Actions for Field Staff
    if (isFieldStaff) {
      VV.Form.SetFieldValue('isFieldStaff', 'True', true);
    } else {
      VV.Form.SetFieldValue('isFieldStaff', 'False');
    }

    const individualIdPresent = VV.Form.GetFieldValue('Individual ID') !== '';
    const userIdPresent = VV.Form.GetFieldValue('UserID') !== '';
    const needsSetIndividual = isProponent && (!individualIdPresent || !userIdPresent);
    if (needsSetIndividual) {
      VV.Form.Template.SetIndividual();
    }
  });
} catch (error) {
  console.error('Error getting current roles:', error);
}

// Register all datagrids at once
try {
  VV.Form.Global.RegisterDatagrids([
    'DG Landowner Businesses',
    'DG Landowners',
    'DG Timber Owner Businesses',
    'DG Timber Owner Individual',
    'DG Operator Businesses',
    'DG Operators',
    'DG Violations',
  ]);
} catch (error) {
  console.error('Error registering datagrids:', error);
}

//Update document path
try {
  VV.Form.Template.UpdateDocumentPath();
} catch (docError) {
  console.error('Error setting document upload path in catch:', docError);
}

// Set tab control
try {
  VV.Form.SetFieldValue('Tab Control', 'Main', true, true);
} catch (tabError) {
  console.error('Error setting tab control:', tabError);
}

// Offline mode check
try {
  if (VV.Form.IsOfflineMode === true) {
    VV.Form.SetFieldValue('Offline Mode', true, true);
  } else {
      VV.Form.SetFieldValue('Offline Mode', false, true);
  }
} catch (error) {
  console.error('Error setting Offline Mode field:', error);
}


try {

    // Initialize variables for initial save handling
    const isSaved = VV.Form.GetFieldValue('Form Saved') === 'True';

    const runPreloadARPInformation = () => {

      const isOpenerARP = window?.opener?.VV?.Form?.DhDocID?.includes('APPLICATION');
      const wasAutoPopulated = VV.Form.GetFieldValue('Was AutoPopulated');

      if (
        (wasAutoPopulated === 'False' ||
          VV.Form.Global.isNullEmptyUndefined(wasAutoPopulated)) &&
        isOpenerARP
      ) {
        // Load ARP data asynchronously - don't block other operations
        VV.Form.Template.LoadDataFromTheARP();
      }

    };

    if (!isSaved) {
      VV.Form.DoAjaxFormSave()
        .then(() => {
          console.log('Initial form save completed.');
          runPreloadARPInformation();
        })
        .catch((err) => {
          console.error('Error during initial form save:', err);
        });
    } else {
      runPreloadARPInformation();
    }


} catch (error) {
  console.error('Error in LoadDataFromTheARP call:', error);
}

